def es_formula(v):
    return isinstance(v, str) and v.startswith("=")
print(es_formula("=A1"))
print(es_formula(3))

regs = ["Lima", "Piura"]
allowed = {"Lima", "Cusco"}
print([r for r in regs if r not in allowed])

def validate_rows(rows, allowed):
    return [r for r in rows if r not in allowed]
print(validate_rows(["Lima", "Piura"], {"Lima", "Cusco"}))

from collections import Counter
def batch_status(files_dict):
    return dict(Counter(files_dict.values()))
print(batch_status({"a": "ok", "b": "corrupt"}))

import hashlib
def h(rows):
    return hashlib.sha1(str(sorted(rows)).encode()).hexdigest()
print(h([2, 1]) == h([1, 2]))

def structural_ok(sheetnames, need):
    return set(sheetnames) >= set(need)
print(structural_ok(["Entrada", "Salida", "Meta"], ["Entrada", "Salida"]))
